#include<bits/stdc++.h>
using namespace std;
int d[300010],lg[300010],a[300010],n,k,f[300010][21],val[300010];
vector<int> mp[300010];
void build(int x,int fa=0)
{
    d[x]=d[fa]+1;
    f[x][0]=fa;
    for(int i=1;(1<<i)<=d[x];i++)
    {
        f[x][i]=f[f[x][i-1]][i-1];
    }
    for(int i:mp[x])
    {
        if(i!=fa)
        {
            build(i,x);
        }
    }
}
int lca(int x,int y)
{
    if(d[x]<d[y])
    {
        swap(x,y);
    }
    while(d[x]>d[y])
    {
        x=f[x][lg[d[x]-d[y]]];
    }
    if(x==y)
    {
        return x;
    }
    for(int i=lg[d[x]];i>=0;i--)
    {
        if(f[x][i]!=f[y][i])
        {
            x=f[x][i];
            y=f[y][i];
        }
    }
    return f[x][0];
}
int ans;
void dfs(int x,int fa=0)
{
    for(int i:mp[x])
    {
        if(i!=fa)
        {
            dfs(i,x);
            val[x]+=val[i];
        }
    }
}
int main()
{
    for(int i=2;i<=300005;i++)
    {
        lg[i]=lg[i/2]+1;
    }
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    for(int i=1;i<n;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        mp[u].push_back(v);
        mp[v].push_back(u);
    }
    build(1);
    for(int i=1;i<n;i++)
    {
        int u=a[i],v=a[i+1];
        val[u]++;
        val[v]++;
        val[lca(u,v)]--;
        val[f[lca(u,v)][0]]--;
    }
    dfs(1);
    for(int i=2;i<=n;i++)
    {
        val[a[i]]--;
    }
    for(int i=1;i<=n;i++)
    {
        printf("%d\n",val[i]);
    }
    return 0;
}
